import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"FAQ и Решение проблем","description":"","frontmatter":{},"headers":[],"relativePath":"ru/faq.md","filePath":"ru/faq.md"}'),i={name:"ru/faq.md"};function l(c,e,r,d,n,m){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="faq-и-решение-проблем" tabindex="-1"><i class="ph ph-question"></i> FAQ и Решение проблем <a class="header-anchor" href="#faq-и-решение-проблем" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; FAQ и Решение проблем&quot;">​</a></h1><p>Здесь собраны ответы на самые частые вопросы и решения типичных проблем, с которыми можно столкнуться при оптимизации WebGL.</p><h2 id="установка-и-демо-сцена" tabindex="-1"><i class="ph ph-package"></i> Установка и Демо-сцена <a class="header-anchor" href="#установка-и-демо-сцена" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; Установка и Демо-сцена&quot;">​</a></h2><details class="details custom-block"><summary>В: Я открыл демо-сцену, а все материалы и объекты в ней розовые!</summary><p><strong>О:</strong> Ваш проект использует URP, а демо-сцена по умолчанию настроена под BiRP. Просто распакуйте пакет по пути <code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code>. Шейдеры обновятся автоматически.</p></details><details class="details custom-block"><summary>В: Я установил плагин, но визуально в игре вообще ничего не меняется.</summary><p><strong>О:</strong> Пройдитесь по этому чек-листу:</p><ul><li>Плагин включен в Project Settings? Скейлеры добавлены и активны?</li><li>Графика в Unity изначально выкручена на максимум? Плагину нечего снижать, если и так стоят низкие настройки.</li><li>Возможно, устройство легко справляется с нагрузкой, и FPS стабилен. Добавьте префаб <code>Dashboard</code> на сцену, чтобы увидеть, что сейчас решает Индексатор.</li><li>Если всё настроено верно, но эффекта нет — свяжитесь с нами, мы поможем разобраться.</li></ul></details><h2 id="разрешение-и-интерфеис-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> Разрешение и Интерфейс (UI) <a class="header-anchor" href="#разрешение-и-интерфеис-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; Разрешение и Интерфейс (UI)&quot;">​</a></h2><details class="details custom-block"><summary>В: Разрешение не меняется (Resolution Scaler не работает).</summary><p><strong>О:</strong> Две самые частые причины:</p><ol><li>Если вы используете <strong>BiRP</strong> и режим <code>RenderTextureScaling</code>: проверьте поле <code>Target Tags</code> в настройках скейлера. Если камера в вашей игре называется иначе (не <code>MainCamera</code>), обязательно впишите её тег. Иначе плагин её просто не найдет.</li><li>Режим <code>NativeBrowserScaling</code> работает исключительно в собранном WebGL-билде. В редакторе Unity он ничего не делает.</li></ol></details><details class="details custom-block"><summary>В: При падении FPS мой UI (интерфейс) тоже становится размытым!</summary><p><strong>О:</strong> Убедитесь, что в BiRP вы выбрали <code>RenderTextureScaling</code>. Сам Canvas при этом должен быть переведен в режим <code>Screen Space - Overlay</code> (либо использовать отдельную UI-камеру).</p></details><details class="details custom-block"><summary>В: Стандартные кнопки UI нажимаются нормально, но мои собственные клики мышкой по 3D-объектам сбились.</summary><p><strong>О:</strong> Базовые события EventSystem автоматически чинятся нашим компонентом <code>WebScaledPhysicsRaycaster</code>. Однако, если вы делаете кастомный рейкаст через код (<code>Camera.ScreenPointToRay()</code>), он будет бить мимо из-за изменения размера текстуры. Используйте специальный метод плагина: <code>WebRaycasterUtility.TryComputeScaledRay()</code>.</p></details><h2 id="метрики-и-поведение-системы" tabindex="-1"><i class="ph ph-chart-line-up"></i> Метрики и Поведение системы <a class="header-anchor" href="#метрики-и-поведение-системы" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; Метрики и Поведение системы&quot;">​</a></h2><details class="details custom-block"><summary>В: Качество графики снизилось из-за лагов. Сейчас FPS снова высокий, но графика не улучшается!</summary><p><strong>О:</strong> Скорее всего сработала защита <strong>Anti Yo-Yo Penalty System</strong>. Плагин временно заблокировал повышение, чтобы избежать мерцания картинки.</p><ul><li>Если графика должна восстанавливаться быстрее, уменьшите параметр <code>Penalty Lockout Duration</code> (например, до 10 секунд).</li><li>Также проверьте параметр <code>Increase Cooldown</code> — возможно, выставлено слишком долгое время ожидания.</li></ul></details><details class="details custom-block"><summary>В: Дашборд постоянно показывает CPU Bottleneck или Unknown, хотя сцена пустая.</summary><p><strong>О:</strong> Обязательно включите <code>Frame Timing Stats</code> в Player Settings. Дополнительно проверьте, что <code>Application.targetFrameRate = -1</code>. Снятие жесткого лимита кадров избавляет метрики от искусственных задержек <code>setTimeout</code> внутри браузера.</p></details><details class="details custom-block"><summary>В: Персонаж или физические объекты начинают дергаться при сильных лагах.</summary><p><strong>О:</strong> Это побочный эффект работы <code>Physics Step Scaler</code>. Он меняет <code>Time.fixedDeltaTime</code>, чтобы спасти процессор от перегрузки. Чтобы движение визуально оставалось плавным, включите режим <code>Interpolate</code> на компоненте <code>Rigidbody</code> вашего персонажа.</p></details><details class="details custom-block"><summary>В: Скейлеры теней включены, но производительность не растет, а тени на месте.</summary><p><strong>О:</strong> Плагин управляет только динамическими (Realtime) тенями. Если освещение в вашей сцене запечено (Baked/Lightmaps), скейлеры на него никак не повлияют.</p></details><h2 id="кастомные-скеилеры" tabindex="-1"><i class="ph ph-code"></i> Кастомные скейлеры <a class="header-anchor" href="#кастомные-скеилеры" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; Кастомные скейлеры&quot;">​</a></h2><details class="details custom-block"><summary>В: Мой кастомный скейлер отлично работает в Editor, но бесследно исчезает в WebGL-билде!</summary><p><strong>О:</strong> Компилятор IL2CPP вырезал его при сборке как &quot;мертвый код&quot;. Всегда добавляйте атрибут <code>[UnityEngine.Scripting.Preserve]</code> над классом вашего кастомного скейлера.</p></details>',16)])])}const h=a(i,[["render",l]]);export{p as __pageData,h as default};
